import{P as t}from"./chunks/PublicUtilityPanel.CsJnb6x3.js";import{T as i}from"./chunks/TrustPilotReviewCollector.C-B8Ui8v.js";import{o,c as r,ag as l,E as e}from"./chunks/framework.B4cHRSx5.js";import"./chunks/theme.D9P57-2E.js";const m=JSON.parse('{"title":"Privacy policy","description":"","frontmatter":{},"headers":[],"relativePath":"en/privacy-policy.md","filePath":"en/privacy-policy.md","lastUpdated":1776731835000}'),n={name:"en/privacy-policy.md"},b=Object.assign(n,{setup(s){return(c,a)=>(o(),r("div",null,[a[0]||(a[0]=l('<h1 id="privacy-policy" tabindex="-1">Privacy policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy policy&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>This page describes how <code>mozg.com.br</code>, its public exports, contact flows and derived apps handle personal data, analytics and technical artifacts.</p><h2 id="data-that-may-be-handled" tabindex="-1">Data that may be handled <a class="header-anchor" href="#data-that-may-be-handled" aria-label="Permalink to &quot;Data that may be handled&quot;">​</a></h2><ul><li>navigation and minimal request metadata required for the public operational surface, such as <code>request_id</code>, <code>timestamp</code>, <code>path</code>, <code>method</code> and equivalent headers;</li><li>information voluntarily sent through direct contact, email or external platforms;</li><li>anonymized or aggregated signals from analytics, ads and public widgets when enabled in the publishing environment.</li></ul><h2 id="purposes" tabindex="-1">Purposes <a class="header-anchor" href="#purposes" aria-label="Permalink to &quot;Purposes&quot;">​</a></h2><ul><li>respond to professional contact and contextualize opportunities;</li><li>measure availability, performance, discoverability and interest across public surfaces;</li><li>keep the portfolio, Storybook, Android apps and technical artifacts auditable;</li><li>reinforce public trust through surfaces such as Trustpilot and complementary public profiles.</li></ul><h2 id="public-integrations" tabindex="-1">Public integrations <a class="header-anchor" href="#public-integrations" aria-label="Permalink to &quot;Public integrations&quot;">​</a></h2><p>Depending on the environment, the site may load integrations such as Cloudflare Web Analytics, Google Analytics, Google Tag Manager, Google Ads, LinkedIn Insight Tag, Meta Pixel, Zoho SalesIQ, Google Custom Search and Trustpilot.</p><p>Each integration follows its own policy and operates as an external public surface. Whenever possible, the configuration favors explicit metadata, async loading and verifiable public URLs.</p><h2 id="apps-and-derived-surfaces" tabindex="-1">Apps and derived surfaces <a class="header-anchor" href="#apps-and-derived-surfaces" aria-label="Permalink to &quot;Apps and derived surfaces&quot;">​</a></h2><ul><li><code>Mozg TWA</code>: published on Google Play as <code>br.com.mozg.twa</code>.</li><li><code>Mozg Hibrido</code>: published on Google Play as <code>com.mozg.android.fizzy</code>.</li><li><code>@mozgbrasil/node-web-components</code>: public npm package with a published Storybook and auditable examples.</li></ul><h2 id="rights-and-contact" tabindex="-1">Rights and contact <a class="header-anchor" href="#rights-and-contact" aria-label="Permalink to &quot;Rights and contact&quot;">​</a></h2><p>For clarification, update or removal requests related to voluntarily submitted data, use:</p><ul><li><a href="mailto:mozgbrasil@gmail.com" target="_blank" rel="noreferrer">Email</a></li><li><a href="https://www.linkedin.com/in/mozgbrasil/" target="_blank" rel="noreferrer">LinkedIn</a></li><li><a href="https://mozg.com.br/en/contact" target="_blank" rel="noreferrer">Contact page</a></li></ul><h2 id="updates" tabindex="-1">Updates <a class="header-anchor" href="#updates" aria-label="Permalink to &quot;Updates&quot;">​</a></h2><p>This policy can evolve when new public surfaces, apps, components or integrations are added to the MOZG ecosystem.</p>',17)),e(t),e(i)]))}});export{m as __pageData,b as default};
